140: /**
141:  * All listener manager stats. @see stats_macros.h
142:  */
143: #define ALL_LISTENER_MANAGER_STATS(COUNTER, GAUGE)                                                 \
144:   COUNTER(listener_added)                                                                          \
145:   COUNTER(listener_create_failure)                                                                 \
146:   COUNTER(listener_create_success)                                                                 \
147:   COUNTER(listener_in_place_updated)                                                               \
148:   COUNTER(listener_modified)                                                                       \
149:   COUNTER(listener_removed)                                                                        \
150:   COUNTER(listener_stopped)                                                                        \
151:   GAUGE(total_filter_chains_draining, NeverImport)                                                 \
152:   GAUGE(total_listeners_active, NeverImport)                                                       \
153:   GAUGE(total_listeners_draining, NeverImport)                                                     \
154:   GAUGE(total_listeners_warming, NeverImport)                                                      \
155:   GAUGE(workers_started, NeverImport)
156: 
157: /**
158:  * Struct definition for all listener manager stats. @see stats_macros.h
